code = """import json
import pandas as pd
from datetime import datetime

# Load the file path from storage
file_path = locals()['var_functions.query_db:20']

# Load the data
with open(file_path, 'r') as f:
    data = json.load(f)

# Create DataFrame
df = pd.DataFrame(data)

# Convert data types
df['CloseUSD'] = df['CloseUSD'].astype(float)
df['Date'] = pd.to_datetime(df['Date'], errors='coerce')

# Filter out rows with invalid dates
df = df.dropna(subset=['Date'])

# Get unique indices
indices = df['Index'].unique()
print('Total indices:', len(indices))
print('Indices:', indices)

# Check date range for each index
summary = df.groupby('Index').agg({
    'Date': ['min', 'max', 'count']
}).round(2)
summary.columns = ['Start_Date', 'End_Date', 'Records']
summary = summary.reset_index()

# Filter indices that have data starting from 2000 or earlier
eligible_indices = summary[summary['Start_Date'] <= '2001-01-01']
print('Indices with data from 2000 or earlier:')
print(eligible_indices[['Index', 'Start_Date', 'End_Date']].to_string(index=False))

print('__RESULT__:')
print(json.dumps({'status': 'data_loaded', 'eligible_count': len(eligible_indices)}))"""

